// Keyword research: Rotating content types and SaaS categories
const categories = [
  { type: 'best-of', template: 'Best {tool_category} for {audience} in 2026', category: 'Best Of' },
  { type: 'comparison', template: '{tool_a} vs {tool_b}: Which Is Better in 2026?', category: 'Comparisons' },
  { type: 'review', template: '{tool_name} Review 2026: Pricing, Features, and Honest Take', category: 'Reviews' },
  { type: 'guide', template: 'How to Set Up {tool_name} for {use_case}', category: 'Guides' }
];

const tools = [
  { name: 'HubSpot CRM', category: 'CRM', audience: 'small business', affiliate: 'hubspot' },
  { name: 'Notion', category: 'Project Management', audience: 'teams', affiliate: 'notion' },
  { name: 'Pipedrive', category: 'CRM', audience: 'sales teams', affiliate: 'pipedrive' },
  { name: 'Monday.com', category: 'Project Management', audience: 'agencies', affiliate: 'monday' },
  { name: 'ClickUp', category: 'Project Management', audience: 'startups', affiliate: 'clickup' },
  { name: 'Freshworks', category: 'CRM', audience: 'growing businesses', affiliate: 'freshworks' },
  { name: 'ConvertKit', category: 'Email Marketing', audience: 'creators', affiliate: 'convertkit' },
  { name: 'Mailchimp', category: 'Email Marketing', audience: 'small business', affiliate: 'mailchimp' },
  { name: 'Zapier', category: 'Automation', audience: 'non-technical users', affiliate: 'zapier' },
  { name: 'Make', category: 'Automation', audience: 'power users', affiliate: 'make' },
  { name: 'n8n', category: 'Automation', audience: 'developers', affiliate: 'n8n' },
  { name: 'Airtable', category: 'Database', audience: 'teams', affiliate: 'airtable' },
  { name: 'Slack', category: 'Communication', audience: 'remote teams', affiliate: 'slack' },
  { name: 'Linear', category: 'Issue Tracking', audience: 'dev teams', affiliate: 'linear' },
  { name: 'Vercel', category: 'Hosting', audience: 'developers', affiliate: 'vercel' },
  { name: 'Cloudflare', category: 'CDN & Security', audience: 'businesses', affiliate: 'cloudflare' },
  { name: 'Supabase', category: 'Backend', audience: 'developers', affiliate: 'supabase' },
  { name: 'Stripe', category: 'Payments', audience: 'SaaS founders', affiliate: 'stripe' }
];

// Pick a random content type and tool
const contentType = categories[Math.floor(Math.random() * categories.length)];
const tool = tools[Math.floor(Math.random() * tools.length)];

// For comparisons, pick a second tool from same category
let tool_b = null;
if (contentType.type === 'comparison') {
  const sameCategory = tools.filter(t => t.category === tool.category && t.name !== tool.name);
  if (sameCategory.length > 0) {
    tool_b = sameCategory[Math.floor(Math.random() * sameCategory.length)];
  } else {
    // Fallback to review if no comparison partner
    contentType.type = 'review';
    contentType.template = '{tool_name} Review 2026: Pricing, Features, and Honest Take';
    contentType.category = 'Reviews';
  }
}

// Build the title
let title = contentType.template
  .replace('{tool_name}', tool.name)
  .replace('{tool_category}', tool.category + ' Tools')
  .replace('{audience}', tool.audience)
  .replace('{use_case}', tool.audience)
  .replace('{tool_a}', tool.name)
  .replace('{tool_b}', tool_b ? tool_b.name : '');

// Build slug
const slug = title.toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');

return [{
  json: {
    title,
    slug,
    content_type: contentType.type,
    category: contentType.category,
    tool_name: tool.name,
    tool_category: tool.category,
    tool_audience: tool.audience,
    tool_affiliate: tool.affiliate,
    tool_b_name: tool_b ? tool_b.name : null,
    tool_b_affiliate: tool_b ? tool_b.affiliate : null,
    date: new Date().toISOString()
  }
}];

const input = $input.first().json;
const topic = $('Keyword & Topic Selector').first().json;

// Extract the generated article text
const articleBody = input.text || input.message?.content || '';

// Build Hugo frontmatter
const frontmatter = `---
title: "${topic.title}"
date: ${topic.date}
draft: false
description: "${topic.title.replace(/"/g, "'")}"
categories: ["${topic.category}"]
tags: ["${topic.tool_name.toLowerCase().replace(/\s+/g, '-')}", "${topic.tool_category.toLowerCase().replace(/\s+/g, '-')}", "${topic.content_type}", "saas-review"]
image: ""
affiliate_links:
  ${topic.tool_affiliate}: ""
${topic.tool_b_affiliate ? '  ' + topic.tool_b_affiliate + ': ""' : ''}
---

`;

const fullPost = frontmatter + articleBody;

return [{
  json: {
    slug: topic.slug,
    title: topic.title,
    content: fullPost,
    category: topic.category,
    tool_name: topic.tool_name,
    date: topic.date
  }
}];
